def seed_if_empty():
    """Если таблица вопросов пуста — заливает стартовый набор."""
    if QuestionRepo.count() == 0:
        for item in SEED:
            QuestionRepo.add(item["q"], item["options"], item["correct"], item["d"])
        return len(SEED)
    return 0
